import {
  createBrowserRouter,
  Outlet,
  redirect,
  RouterProvider,
} from "react-router-dom";

import { useEffect, useState } from "react";
import Layout from "./components/Layout/Layout";
import ServerNav from "./components/ServerNav/ServerNav";
import Sidebar from "./components/Sidebar/Sidebar";
import Chat from "./pages/DM/Chat";
import Login from "./pages/Auth/Login";
import Register from "./pages/Auth/Register";
import Loading from "./pages/LoadingScreen/Loading";

function App() {
  const [token, setToken] = useState(null);
  const [isAuth, setIsAuth] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  useEffect(() => {
    console.log("USE EFFECT")
    const token = localStorage.getItem("token");
    const expiryDate = localStorage.getItem("expiryDate");

    if (!token || !expiryDate) {
      setIsLoading(false);
      return;
    }

    if (new Date(expiryDate) <= new Date()) {
      setIsLoading(false);
      logoutHandler();
      return;
    }

    setToken(token);
    setIsAuth(true);

    const fetchData = async () => {
      try {
        const response = await fetch("/channels/direct-messages", {
          headers: {
            Authorization: "Bearer " + token,
          },
        });

        if (!response.ok) {
          console.log(response);
          throw new Error("An error has occurred.");
        }

        const messagesList = await response.json();

        await new Promise((r) => setTimeout(r, 2000));
      } catch (err) {
        console.log(err);
      } finally {
        setIsLoading(false);
      }
    };

    fetchData();
  }, []);

  const logoutHandler = () => {
    localStorage.removeItem("token");
    localStorage.removeItem("expiryDate");
    setToken(null);
    setIsAuth(false);
  };

  const loginHandler = async (formData) => {
    const data = { email: formData.email, password: formData.password };
    try {
      const response = await fetch("/auth/login", {
        method: "POST",
        body: JSON.stringify(data),
        headers: { "Content-Type": "application/json" },
      });
      // check status
      let responseData = await response.json();
      console.log(responseData);

      // 7 days
      const remainingTimeMs = 7 * 24 * 60 * 60 * 1000;
      const expiryDate = new Date(new Date().getTime() + remainingTimeMs);
      localStorage.setItem("expiryDate", expiryDate.toISOString());
      localStorage.setItem("token", responseData.token);
      setToken(responseData.token);
      setIsAuth(true);

      // redirect page
    } catch (err) {
      console.log(err);
    }
  };

  if (isLoading) {
    return <Loading></Loading>;
  }

  const router = createBrowserRouter([
    {
      path: "/",
      element: (
        <Layout
          nav={isAuth && <ServerNav token={token} />}
          sidebar={isAuth && <Sidebar token={token} />}
        >
          <Outlet></Outlet>
        </Layout>
      ),
      children: [
        {
          path: "/register",
          element: <Register />,
        },
        {
          path: "/login",
          loader: () => {
            if (isAuth) return redirect("/");
            return null;
          },
          element: <Login loginHandler={loginHandler} />,
        },
        {
          path: "/",
          loader: () => {
            if (!isAuth) return redirect("/login");
            return null;
          },
          element: <Chat></Chat>,
        },

        {
          path: "/friends",
          loader: () => {
            if (!isAuth) return redirect("/login");
            return null;
          },
          element: <Chat></Chat>,
        },
      ],
    },
  ]);

  return <RouterProvider router={router}></RouterProvider>;
}

export default App;
